          .map(function (b) {
            if (!b || typeof b !== 'object') return '';
            const val = num(b.value);
            if (val == null) return '';
            const units = num(b.units);
            const time = b.time ? String(b.time) : '';
            let s = String(val);
            if (units != null && units > 0) s += ' U/h ' + units;
            if (time) s += '@' + time;
            return s;
          })
          .filter(Boolean)
